// Parse the stock list from file or Google Sheets
// Replace this with Google Sheets input if preferred

const rawText = $input.first().json.data || '';
const lines = rawText.split('\n').filter(l => l.trim() && !l.startsWith('#'));
const tickers = lines.map(l => l.trim().toUpperCase());

console.log(`Loaded ${tickers.length} tickers: ${tickers.join(', ')}`);

// Output as array for downstream loop
return tickers.map(ticker => ({ json: { ticker } }));

// ══════════════════════════════════════════════
// FULL INDICATOR ENGINE — runs per ticker
// ══════════════════════════════════════════════
// This is a simplified version. For production,
// call your Python indicator_engine.py via Execute Command node.

const ticker = $input.first().json.ticker;

// ── Fetch from Yahoo Finance (via HTTP request below) ──
// This node receives the OHLCV JSON from the HTTP node
const ohlcv = $input.first().json.ohlcv || [];

if (!ohlcv || ohlcv.length < 30) {
  return [{ json: { ticker, error: 'Insufficient data', signal: 'UNKNOWN' } }];
}

const closes  = ohlcv.map(d => d.close);
const highs   = ohlcv.map(d => d.high);
const lows    = ohlcv.map(d => d.low);
const volumes = ohlcv.map(d => d.volume);
const n       = closes.length;

// ── Helpers ──────────────────────────────────
const mean = arr => arr.reduce((a,b) => a+b, 0) / arr.length;
const last  = arr => arr[arr.length - 1];
const prev  = arr => arr[arr.length - 2];

// ── RSI (14) ─────────────────────────────────
function calcRSI(closes, period=14) {
  const deltas = closes.slice(1).map((c,i) => c - closes[i]);
  const gains  = deltas.map(d => d > 0 ? d : 0);
  const losses = deltas.map(d => d < 0 ? -d : 0);
  const avgG   = mean(gains.slice(-period));
  const avgL   = mean(losses.slice(-period));
  return avgL === 0 ? 100 : 100 - (100 / (1 + avgG / avgL));
}

// ── EMA ──────────────────────────────────────
function ema(arr, period) {
  const k = 2 / (period + 1);
  let e = arr[0];
  for (let i=1; i<arr.length; i++) e = arr[i]*k + e*(1-k);
  return e;
}

// ── MACD ─────────────────────────────────────
const ema12 = ema(closes, 12);
const ema26 = ema(closes, 26);
const macd  = ema12 - ema26;

// ── SMA ──────────────────────────────────────
const sma20  = mean(closes.slice(-20));
const sma50  = mean(closes.slice(-50));
const sma200 = closes.length >= 200 ? mean(closes.slice(-200)) : null;

// ── Bollinger Bands ───────────────────────────
const std20  = Math.sqrt(closes.slice(-20).map(c=>(c-sma20)**2).reduce((a,b)=>a+b)/20);
const bbUpper = sma20 + 2*std20;
const bbLower = sma20 - 2*std20;
const bbPos   = ((last(closes) - bbLower) / (bbUpper - bbLower) * 100).toFixed(1);

// ── Volume ───────────────────────────────────
const volAvg20 = mean(volumes.slice(-20));
const volRatio = (last(volumes) / volAvg20).toFixed(2);

// ── RSI signal ───────────────────────────────
const rsi = calcRSI(closes);
const rsiSignal = rsi >= 70 ? 'overbought' : rsi >= 55 ? 'bullish' :
                  rsi >= 45 ? 'neutral'    : rsi >= 30 ? 'bearish' : 'oversold';

// ── Scoring ──────────────────────────────────
let score = 50;
if (rsi > 50 && rsi < 65)  score += 12;
else if (rsi < 35)          score -= 15;
if (macd > 0)               score += 10;
else                        score -= 10;
if (last(closes) > sma50)   score += 10;
else                        score -= 10;
if (sma200 && last(closes) > sma200) score += 8;
if (volRatio > 1.5 && last(closes) > prev(closes)) score += 12;

score = Math.max(0, Math.min(100, score));

const signal = score >= 72 ? 'STRONG BUY' :
               score >= 58 ? 'BUY'        :
               score >= 42 ? 'NEUTRAL'    :
               score >= 28 ? 'SELL'       : 'STRONG SELL';

const price   = last(closes);
const change1d = ((price - prev(closes)) / prev(closes) * 100).toFixed(2);

return [{ json: {
  ticker,
  price,
  change_1d: parseFloat(change1d),
  signal,
  composite_score: parseFloat(score.toFixed(1)),
  indicators: {
    rsi: parseFloat(rsi.toFixed(1)),
    rsi_signal: rsiSignal,
    macd: parseFloat(macd.toFixed(4)),
    sma20, sma50,
    bb_position: parseFloat(bbPos),
    volume_ratio: parseFloat(volRatio),
  }
}}];

// Transform Yahoo Finance response into clean OHLCV array
const response = $input.first().json;
const ticker   = $input.first().json.ticker || $('node_parse').first().json.ticker;

try {
  const result    = response.chart.result[0];
  const timestamps = result.timestamp;
  const quote     = result.indicators.quote[0];

  const ohlcv = timestamps.map((ts, i) => ({
    date:   new Date(ts * 1000).toISOString().split('T')[0],
    open:   quote.open[i],
    high:   quote.high[i],
    low:    quote.low[i],
    close:  quote.close[i],
    volume: quote.volume[i],
  })).filter(d => d.close !== null);

  return [{ json: { ticker, ohlcv } }];
} catch(e) {
  return [{ json: { ticker, ohlcv: [], error: e.message } }];
}

// Simple keyword-based sentiment from headlines
const data    = $input.first().json;
const ticker  = $('node_parse').first().json.ticker;
const news    = data.news || [];

const POS = ['surge','rally','beat','record','growth','strong','upgrade','buy','bullish','profit','gain','rise','high'];
const NEG = ['fall','drop','miss','loss','weak','downgrade','sell','bearish','decline','crash','concern','risk'];

let sentimentScore = 0;
const headlines = news.slice(0, 5).map(n => {
  const title = n.title || '';
  const lower = title.toLowerCase();
  const pos   = POS.filter(w => lower.includes(w)).length;
  const neg   = NEG.filter(w => lower.includes(w)).length;
  sentimentScore += (pos - neg);
  return title;
});

sentimentScore = Math.max(-1, Math.min(1, sentimentScore / Math.max(headlines.length, 1)));

return [{ json: {
  ticker,
  news_sentiment: parseFloat(sentimentScore.toFixed(2)),
  sentiment_label: sentimentScore > 0.1 ? 'positive' : sentimentScore < -0.1 ? 'negative' : 'neutral',
  headlines
}}];

// Aggregate all stock analyses into one daily report
const results = $input.all().map(i => i.json);

// Sort by composite score descending
const valid = results.filter(r => !r.error).sort((a,b) => b.composite_score - a.composite_score);

// Categorize
const strongBuys = valid.filter(r => r.signal === 'STRONG BUY');
const buys       = valid.filter(r => r.signal === 'BUY');
const neutrals   = valid.filter(r => r.signal === 'NEUTRAL');
const sells      = valid.filter(r => ['SELL','STRONG SELL'].includes(r.signal));

const fmt = (r) => {
  const ind = r.indicators || {};
  return `${r.signal.padEnd(12)} ${r.ticker.padEnd(14)} Score:${String(r.composite_score).padStart(5)} RSI:${String(ind.rsi || '-').padStart(5)} 1D:${r.change_1d > 0 ? '+' : ''}${r.change_1d}%`;
};

const lines = [
  `📊 DAILY EQUITY RESEARCH REPORT — ${new Date().toLocaleDateString('en-IN')}`,
  `${'═'.repeat(60)}`,
  ``,
  `📈 MARKET BREADTH`,
  `  🟢 Strong Buy: ${strongBuys.length}  🟢 Buy: ${buys.length}  🟡 Neutral: ${neutrals.length}  🔴 Sell: ${sells.length}`,
  ``,
  `🚀 TOP MOMENTUM (Strong Buy)`,
  ...strongBuys.slice(0,5).map(r => `  ✅ ${fmt(r)}`),
  ...buys.slice(0,3).map(r => `  🟢 ${fmt(r)}`),
  ``,
  `⚠️  STOCKS TO AVOID / WATCH FOR SHORTS`,
  ...sells.slice(0,5).map(r => `  🔴 ${fmt(r)}`),
  ``,
  `📋 ALL RESULTS`,
  ...valid.map(r => `  ${r.signal.padEnd(12)} ${fmt(r)}`),
  ``,
  `Generated by Equity Research Assistant`,
];

return [{ json: {
  report_text: lines.join('\n'),
  summary: {
    date: new Date().toISOString().split('T')[0],
    total: results.length,
    strong_buys: strongBuys.length,
    buys: buys.length,
    neutrals: neutrals.length,
    sells: sells.length,
  },
  top_picks:    strongBuys.concat(buys).slice(0,5),
  avoid_list:   sells.slice(0,5),
  all_results:  valid,
}}];
